#!/usr/bin/env node
// scripts/build-pledge-ics.mjs
//
// Generate public/pledge.ics — a one-year rolling calendar subscription
// of weekly prayer events for Foster Crisis. Users add the feed once to
// Apple Calendar / Google Calendar / Outlook / Fantastical and get a
// Sunday-morning meditation + action prompt every week.
//
// No subscriber list. No backend. The file is regenerated by the pages
// workflow on every deploy and served as a static asset; calendar
// clients poll it on their own schedule.
//
// Run locally:   node scripts/build-pledge-ics.mjs

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const here = path.dirname(fileURLToPath(import.meta.url));
const OUT_PATH = path.join(here, '..', 'public', 'pledge.ics');

const WEEKS = 52;
const START_HOUR = 9; // 9:00 Sunday local time (floating — no TZ)
const DURATION_MIN = 20;

