function pad(n) { return String(n).padStart(2, '0'); }

/** Floating local-time date format: YYYYMMDDTHHMMSS — no Z, no TZID. */
function fmtLocal(y, m, d, hh, mm) {
  return `${y}${pad(m)}${pad(d)}T${pad(hh)}${pad(mm)}00`;
}

/** UTC timestamp for DTSTAMP: YYYYMMDDTHHMMSSZ */
function fmtUtc(date) {
  return (
    date.getUTCFullYear().toString() +
    pad(date.getUTCMonth() + 1) +
    pad(date.getUTCDate()) +
    'T' +
    pad(date.getUTCHours()) +
    pad(date.getUTCMinutes()) +
    pad(date.getUTCSeconds()) +
    'Z'
  );
}

/** Escape a text value for ICS. */
function esc(v) {
  return String(v)
    .replace(/\\/g, '\\\\')
    .replace(/;/g, '\\;')
    .replace(/,/g, '\\,')
    .replace(/\n/g, '\\n');
}

/** Fold long lines at 75 octets per RFC 5545 §3.1. */
function fold(line) {
  if (line.length <= 75) return line;
  const out = [];
  let rest = line;
  out.push(rest.slice(0, 75));
  rest = rest.slice(75);
  while (rest.length > 74) {
    out.push(' ' + rest.slice(0, 74));
    rest = rest.slice(74);
  }
  if (rest.length) out.push(' ' + rest);
  return out.join('\r\n');
}

/** Given any date, return the next Sunday (same day if it IS Sunday). */
function nextSunday(from) {
  const d = new Date(from);
  d.setHours(0, 0, 0, 0);
  const delta = (7 - d.getDay()) % 7;
  d.setDate(d.getDate() + delta);
  return d;
}

function buildIcs() {
  const now = new Date();
  const start = nextSunday(now);

  const lines = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//fostercrisis.com//Pledge Calendar//EN',
    'CALSCALE:GREGORIAN',
    'METHOD:PUBLISH',
    'X-WR-CALNAME:Foster Crisis — Weekly Prayer',
    'X-WR-CALDESC:A weekly Sunday-morning meditation on the 329,000 children in American foster care tonight — scripture, prompt, and one action.',
    'REFRESH-INTERVAL;VALUE=DURATION:P1D',
    'X-PUBLISHED-TTL:P1D',
  ];

  const stamp = fmtUtc(now);

  for (let i = 0; i < WEEKS; i++) {
    const d = new Date(start);
    d.setDate(start.getDate() + i * 7);
    const y = d.getFullYear();
    const m = d.getMonth() + 1;
    const day = d.getDate();
    const dtstart = fmtLocal(y, m, day, START_HOUR, 0);
    const endHour = START_HOUR;
    const endMin = DURATION_MIN; // assumes < 60
    const dtend = fmtLocal(y, m, day, endHour, endMin);

    const p = PROMPTS[i % PROMPTS.length];
    const uid = `pledge-${y}${pad(m)}${pad(day)}@fostercrisis.com`;

    lines.push(
      'BEGIN:VEVENT',
      fold('UID:' + uid),
      'DTSTAMP:' + stamp,
      'DTSTART:' + dtstart,
      'DTEND:' + dtend,
      fold('SUMMARY:' + esc(p.summary)),
      fold('DESCRIPTION:' + esc(p.description)),
      fold('URL;VALUE=URI:https://fostercrisis.com/#solution'),
      'CATEGORIES:Foster Crisis,Prayer',
      'END:VEVENT'
    );
  }

  lines.push('END:VCALENDAR');
  return lines.join('\r\n') + '\r\n';
}

const ics = buildIcs();
fs.mkdirSync(path.dirname(OUT_PATH), { recursive: true });
fs.writeFileSync(OUT_PATH, ics, 'utf8');
console.log(`✓ wrote ${OUT_PATH} (${WEEKS} weekly events)`);
